import React from 'react';
import styles from './benefits.module.css';
import Title from '../../title';
import features from './benefits.json';
import Feature from './feature';

const Benefits: React.FC = () => {
  return (
    <div className={styles.benefits}>
        <div className='container'>
            <div className={styles.container_inner}>
                <div className={styles.left_side}>
                    <Title level="h2" className={styles.title}>Clean and fragrant soy wax</Title>
                    <Title level="h6" className={styles.subtitle}>Made for your home and for your wellness</Title>
                    <div className={styles.wrapper_features}>
                        {features.map(({ id, name, desc, img }) => (
                            <div key={id}>
                                <Feature name={name} desc={desc} imgSrc={img} />
                            </div>

                        ))}
                    </div>

                    <div className={styles.wrapper_features}>
  {features.map(({ id, name, desc, img }) => (
    <div key={id}>
      <Feature name={name} desc={desc} imgSrc={img} />
    </div>
  ))}
</div>

                </div>
                <div className={styles.right_side}>
                </div>
            </div>
        </div>

    </div>
  )
}

export default Benefits;
